+        b"h2",
+        b"f",
+        NOW + 60_000,
+        HashFieldTtlCondition::None,
+        NOW,
+    );
+    assert_eq!(store.hash_field_ttl_carrier_count(), 2);
+
+    store.hash_field_persist(b"h1", b"f");
